import type { ModelMessage } from "ai";
import { describe, expect, it } from "vitest";
import type {
  ActualTokenUsage,
  ActualTokenUsageInput,
  CheckpointLine,
  CheckpointMessage,
  CompactionConfig,
  CompactionResult,
  CompactionSegment,
  CompactionSummary,
  ContextUsage,
  ContinuationVariant,
  Message,
  MessageLine,
  PreparedCompaction,
  PreparedCompactionSegment,
  PreparedCompactionV2,
  PruningConfig,
  SessionFileLine,
  SessionHeaderLine,
  SessionMetadata,
  StructuredState,
  TodoItem,
} from "./compaction-types";

// Helper to create a valid ModelMessage for testing
function createModelMessage(overrides: Partial<ModelMessage> = {}): ModelMessage {
  return {
    role: "user",
    content: "test message",
    ...overrides,
  };
}

// ============================================================
// Message Interface Tests
// ============================================================
describe("Message", () => {
  it("requires id, createdAt, and modelMessage fields", () => {
    const message: Message = {
      id: "msg_123",
      createdAt: new Date(),
      modelMessage: createModelMessage(),
    };

    expect(message.id).toBe("msg_123");
    expect(message.createdAt).toBeInstanceOf(Date);
    expect(message.modelMessage).toBeDefined();
  });

  it("has optional originalContent field", () => {
    const messageWithOptional: Message = {
      id: "msg_123",
      createdAt: new Date(),
      modelMessage: createModelMessage(),
      originalContent: "original text",
    };

    const messageWithoutOptional: Message = {
      id: "msg_456",
      createdAt: new Date(),
      modelMessage: createModelMessage(),
    };

    expect(messageWithOptional.originalContent).toBe("original text");
    expect(messageWithoutOptional.originalContent).toBeUndefined();
  });
});

// ============================================================
// CheckpointMessage Interface Tests
// ============================================================
describe("CheckpointMessage", () => {
  it("requires all core fields: id, createdAt, isSummary, message", () => {
    const checkpoint: CheckpointMessage = {
      id: "checkpoint_123",
      createdAt: Date.now(),
      isSummary: true,
      message: createModelMessage(),
    };

    expect(typeof checkpoint.id).toBe("string");
    expect(typeof checkpoint.createdAt).toBe("number");
    expect(typeof checkpoint.isSummary).toBe("boolean");
    expect(checkpoint.message).toBeDefined();
  });

  it("has optional originalContent field", () => {
    const checkpointWithOptional: CheckpointMessage = {
      id: "checkpoint_123",
      createdAt: Date.now(),
      isSummary: false,
      message: createModelMessage(),
      originalContent: "original content",
    };

    const checkpointWithoutOptional: CheckpointMessage = {
      id: "checkpoint_456",
      createdAt: Date.now(),
      isSummary: true,
      message: createModelMessage(),
    };

    expect(checkpointWithOptional.originalContent).toBe("original content");
    expect(checkpointWithoutOptional.originalContent).toBeUndefined();
  });

  it("createdAt uses Date.now() format (number)", () => {
    const now = Date.now();
    const checkpoint: CheckpointMessage = {
      id: "checkpoint_123",
      createdAt: now,
      isSummary: false,
      message: createModelMessage(),
    };

    expect(checkpoint.createdAt).toBe(now);
    expect(Number.isFinite(checkpoint.createdAt)).toBe(true);
  });
});

// ============================================================
// SessionMetadata Interface Tests
// ============================================================
describe("SessionMetadata", () => {
  it("requires all fields", () => {
    const metadata: SessionMetadata = {
      completionTokens: 100,
      createdAt: Date.now(),
      promptTokens: 500,
      sessionId: "session_abc",
      summaryMessageId: "summary_123",
      updatedAt: Date.now(),
    };

    expect(metadata.completionTokens).toBe(100);
    expect(metadata.promptTokens).toBe(500);
    expect(metadata.sessionId).toBe("session_abc");
    expect(metadata.summaryMessageId).toBe("summary_123");
  });

  it("summaryMessageId can be null (no compaction yet)", () => {
    const metadataNoCompaction: SessionMetadata = {
      completionTokens: 0,
      createdAt: Date.now(),
      promptTokens: 0,
      sessionId: "session_new",
      summaryMessageId: null,
      updatedAt: Date.now(),
    };

    expect(metadataNoCompaction.summaryMessageId).toBeNull();
  });

  it("summaryMessageId is string | null type", () => {
    const withSummary: SessionMetadata = {
      completionTokens: 100,
      createdAt: Date.now(),
      promptTokens: 500,
      sessionId: "session_abc",
      summaryMessageId: "summary_123",
      updatedAt: Date.now(),
    };

    const withoutSummary: SessionMetadata = {
      completionTokens: 0,
      createdAt: Date.now(),
      promptTokens: 0,
      sessionId: "session_abc",
      summaryMessageId: null,
      updatedAt: Date.now(),
    };

    expect(typeof withSummary.summaryMessageId).toBe("string");
    expect(withoutSummary.summaryMessageId).toBeNull();
  });
});

// ============================================================
// CompactionConfig Interface Tests
// ============================================================
describe("CompactionConfig", () => {
  it("allows empty config (all fields optional)", () => {
    const emptyConfig: CompactionConfig = {};

    expect(emptyConfig.enabled).toBeUndefined();
    expect(emptyConfig.contextLimit).toBeUndefined();
    expect(emptyConfig.maxTokens).toBeUndefined();
  });

  it("enabled field has default false according to JSDoc", () => {
    const config: CompactionConfig = {
      enabled: false,
    };

    expect(config.enabled).toBe(false);
  });

  it("enabled can be set to true", () => {
    const config: CompactionConfig = {
      enabled: true,
    };

    expect(config.enabled).toBe(true);
  });

  it("contextLimit can be set to 0 for unlimited context", () => {
    const unlimitedConfig: CompactionConfig = {
      contextLimit: 0,
    };

    const limitedConfig: CompactionConfig = {
      contextLimit: 128000,
    };

    expect(unlimitedConfig.contextLimit).toBe(0);
    expect(limitedConfig.contextLimit).toBe(128000);
  });

  it("keepRecentTokens has default 2000 according to JSDoc", () => {
    const config: CompactionConfig = {
      keepRecentTokens: 2000,
    };

    expect(config.keepRecentTokens).toBe(2000);
  });

  it("maxTokens has default 8000 according to JSDoc", () => {
    const config: CompactionConfig = {
      maxTokens: 8000,
    };

    expect(config.maxTokens).toBe(8000);
  });

  it("reserveTokens has default 2000 according to JSDoc", () => {
    const config: CompactionConfig = {
      reserveTokens: 2000,
    };

    expect(config.reserveTokens).toBe(2000);
  });

  it("thresholdRatio has default 0.5 according to JSDoc", () => {
    const config: CompactionConfig = {
      thresholdRatio: 0.5,
    };

    expect(config.thresholdRatio).toBe(0.5);
  });

  it("speculativeStartRatio valid range is 0.15 to 0.95", () => {
    const minRatio: CompactionConfig = {
      speculativeStartRatio: 0.15,
    };

    const maxRatio: CompactionConfig = {
      speculativeStartRatio: 0.95,
    };

    expect(minRatio.speculativeStartRatio).toBe(0.15);
    expect(maxRatio.speculativeStartRatio).toBe(0.95);
  });

  it("summarizeFn is a custom async function", async () => {
    const config: CompactionConfig = {
      summarizeFn: async (messages: ModelMessage[], previousSummary?: string) => {
        return `Summary of ${messages.length} messages. Previous: ${previousSummary ?? "none"}`;
      },
    };

    const result = await config.summarizeFn!([createModelMessage()], "old summary");
    expect(result).toContain("Summary of 1 messages");
    expect(result).toContain("old summary");
  });

  it("full config with all options", () => {
    const fullConfig: CompactionConfig = {
      contextLimit: 128000,
      enabled: true,
      keepRecentTokens: 3000,
      maxTokens: 12000,
