      limit: 100000,
      percentage: 0,
      remaining: 100000,
      source: "estimated",
      used: 0,
    };

    const highUsage: ContextUsage = {
      limit: 100000,
      percentage: 100,
      remaining: 0,
      source: "actual",
      used: 100000,
